INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00403', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「望高樓是臺灣的第一座燈塔，比鵝鑾鼻燈塔還早八十七年。淡水河口附近有兩條咕咾石珊瑚礁，退 潮時會露出海面，其形宛如龍蝦的二條長腳，當視野不清時，『龍蝦礁』屢被航海者誤認為港口，因 此古人稱之為假港。這對出入港口的船隻非常危險，所以船戶合資興建一座傳統塔式建築，取樓高可 以遠望之意，命名『望高樓』。」 根據上文，下列有關「望高樓」的敘述，最正確的是：', '["位在鵝鑾鼻", "常被誤認為假港", "因「龍蝦礁」而興建", "「龍蝦礁」退潮時，塔樓才會露出海面"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00404', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「床鋪重新鋪整，看起來像是沒人睡過一樣。隔天或許會住進來新的病人，帶著新的疾病與新的故事， 我們將很快忘記前一位在那張床上住過的病人。醫院裡的病人，都是過境旅客。」 根據上文，下列敘述何者最貼近文意？', '["機場宜效法醫院消毒，避免病菌蔓延", "醫生應儘快忘記病人，迎向後續挑戰", "旅行易水土不服患病，醫院都是旅客", "醫生已看盡生死往復，體悟人世無常"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00405', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '西諺云：「最後笑的那個人，多半沒聽懂笑話。」其涵義接近下列那個選項？', '["一傅眾咻", "入境隨俗", "隨聲附和", "眾口鑠金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00406', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「流行歌曲最有趣的是，每一首歌都不能完全描繪你的遭遇，但每一首歌都可以讓人投射大分量情緒 認同，這是一種情感上的放血與刮痧。那些沒人能了解的孤單，遭到背叛的痛楚，人生沒有明天的絕 境，再努力也無法百尺竿頭更進一步的窩囊。流行歌，神奇地，在差異中找到一個情緒上最大公約數。」 下列選項，何者最接近上文意旨？', '["此夜曲中聞折柳，何人不起故園情", "此曲只應天上有，人間能得幾回聞", "曲罷不知人在否，餘音嘹亮尚飄空", "離歌且莫翻新闋， 一曲能教腸寸結"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00407', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「正面的『怕輸』心理，會促使人為達到理想目標，考慮得更加仔細與周密，因而為此做更多的功課， 並且增加很多的責任感。」 下列選項，何者最能說明上文的意旨？', '["輸贏不用在乎，過程才重要", "為了成功，必須強化自己的心靈", "仔細和周密的考慮，可以增加責任感", "「怕輸」的正面心理，可以作為前進的動力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00408', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「組織一個機關，第一件要緊的事就是印製信紙信封。說也奇怪，社會的人士真有眼光，看見你用的 信封信紙印著機關的名字，頓時對你增加三分信仰。信紙上要是再印上幾個英文字，你的人格就算是 有了擔保。」 作者在字裡行間想要表達的意旨是：', '["信封信紙代表一個機關的門面，輕忽不得", "信封信紙的式樣充分顯示一個機關的品味", "信紙加上英文，表示這個機關充分國際化", "大眾對信封信紙的重視，是對表象的迷信"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00409', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「靜不是停滯，靜不是休止，靜是莊嚴的工作、熱切的活動的前奏，好似音樂演奏會啟幕前，那寂然 無嘩的臺前。只有在最深度的寧靜，最高度靜謐中，你才可以慢慢的調理你的弦索，時間一到，它才 可以發出動人的節響來。只有在幽獨、寧靜之中，你才可以悄然的蓄集你生命的力量，如涓滴之歸向 大海，如塵沙之堆積丘山，不知不覺間，形成了你的強力與偉大。」 下列選項的詮釋，最正確的是：', '["靜謐中最能積累生命的能量", "靜謐是莊嚴熱切工作所必備", "調弦發響是寧靜的最高境界", "涓滴歸海是寧靜致遠的表徵"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00410', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「藝術創作的心理活動中，自覺與非自覺，意識與無意識，都是互相影響、互相轉化的，書法藝術創 作亦是如此。一方面是書法家自己有自覺、有意識的活動；另一方面又有不少無自覺、無意識的因素， 這些都是創作心理的顯著特點。」上文所言藝術創作的心理活動中的「非自覺與無意識」，最有可能 是指：', '["遣詞用字", "運用典故", "設想主題", "出現靈感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00411', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「對於孩子教導，父母有時就是不斷提醒，毫不厭煩地提醒。只要我們看得出孩子願意改變的心，就 應該要拿出耐心來，給孩子機會，因為他們畢竟還沒長大成熟。只要父母不放棄，孩子永遠有機會。」 上文所述，與下列那個成語意思相近？', '["循循善誘", "青出於藍", "教無常師", "師心自用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00412', 'judicial-57f41407', 'judicial-57f41407-moex-112-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「還記得剛到哈佛，在福格藝術館首次看到梵谷〈自畫像〉、雷諾〈少女〉那份興奮驚奇神情，更不用 說瑞布藍特與莫內了。每番總是在這些名家作品之前，佇立良久。此次重看，似乎格外多情。走下底 樓，展出的是一個古老文明的歷史：殷商銅器、漢玉、明清字畫，以及那座靜坐千年、剝落殆盡的木 菩薩；收藏雖富，自己免不了有『抛卻自家無盡藏，沿門托鉢效貧兒』的哀傷。」 上文作者言「抛卻自家無盡藏，沿門托鉢效貧兒」，他的意思是：', '["哈佛福格藝術館的收藏，果真遠近馳名", "文明古國不知珍惜，以致文物流落外邦", "自己國家的文物也很多，不用羨慕美國", "自己國家太貧窮，無法有像樣的博物館"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "7446667e8115", "answer_pdf_sha1": "bc86434646c5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
